/*
 * pow() test harness — prints (x_hex, y_hex, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly pow  (test_pow_opt.elf)
 *   2. Linked with toolchain's default pow       (test_pow_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x, double y)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    volatile double vy = y;
    g_acc += pow(vx, vy);
}

static void emit_u(uint64_t bits_x, uint64_t bits_y)
{
    emit(u2d(bits_x), u2d(bits_y));
}
#else
static void emit(double x, double y)
{
    double r = pow(x, y);
    printf("%016llx %016llx %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u(y),
           (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits_x, uint64_t bits_y)
{
    emit(u2d(bits_x), u2d(bits_y));
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: IEEE 754 special value combinations (12) --- */
    emit(0.0, 0.0);                                                         /* 0^0 = 1 */
    emit(0.0, 1.0);                                                         /* 0^1 = 0 */
    emit(0.0, -1.0);                                                        /* 0^(-1) = +Inf */
    emit(-0.0, 1.0);                                                        /* (-0)^odd = -0 */
    emit(-0.0, 2.0);                                                        /* (-0)^even = +0 */
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);                   /* qNaN base, exp=1 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);                   /* base=1, qNaN exp */
    emit_u(0x7ff0000000000000ULL, 0x3fe0000000000000ULL);                   /* +Inf^0.5 = +Inf */
    emit_u(0xfff0000000000000ULL, 0x4000000000000000ULL);                   /* -Inf^2 = +Inf (even) */
    emit_u(0xfff0000000000000ULL, 0x4008000000000000ULL);                   /* -Inf^3 = -Inf (odd) */
    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL);                   /* 1^+Inf = 1 (special rule) */
    emit_u(0x7ff0000000000000ULL, 0x7ff0000000000000ULL);                   /* +Inf^+Inf = +Inf */

    /* --- Section 2: Subnormal bases with normal exponents (6) --- */
    emit_u(0x0000000000000001ULL, 0x3ff0000000000000ULL);                   /* min pos subnormal: 2^-1074, exp=1 */
    emit_u(0x8000000000000001ULL, 0x4000000000000000ULL);                   /* min neg subnormal, exp=2 (even -> +) */
    emit_u(0x0008000000000000ULL, 0x4000000000000000ULL);                   /* mid pos subnormal, exp=2 */
    emit_u(0x8008000000000000ULL, 0x4008000000000000ULL);                   /* mid neg subnormal, exp=3 (odd -> -) */
    emit_u(0x000fffffffffffffULL, 0x3fe0000000000000ULL);                   /* max pos subnormal: just below DBL_MIN, exp=0.5 */
    emit_u(0x800fffffffffffffULL, 0x4000000000000000ULL);                   /* max neg subnormal, exp=2 (even -> +) */

    /* --- Section 3: Normal boundary bases (6) --- */
    emit(DBL_MIN, 1.0);                                                     /* 2^-1022, smallest normal */
    emit(-DBL_MIN, 1.0);                                                    /* negative smallest normal */
    emit_u(0x0010000000000001ULL, 0x4000000000000000ULL);                   /* one ULP above DBL_MIN, exp=2 */
    emit(DBL_MAX, 1.0);                                                     /* largest finite double */
    emit(-DBL_MAX, 1.0);                                                    /* negative largest finite */
    emit(DBL_MAX, 0.5);                                                     /* sqrt(DBL_MAX): should be finite */

    /* --- Section 4: Near-1.0 base ULP cluster, exp=2 (8) --- */
    emit_u(0x3fefffffffffffffULL, 0x4000000000000000ULL);                   /* one ULP below 1.0, exp=2 */
    emit_u(0x3ff0000000000000ULL, 0x4000000000000000ULL);                   /* 1.0^2 = 1 */
    emit_u(0x3ff0000000000001ULL, 0x4000000000000000ULL);                   /* one ULP above 1.0, exp=2 */
    emit_u(0x3fefffffff000000ULL, 0x4000000000000000ULL);                   /* several ULPs below 1.0, exp=2 */
    emit_u(0x3ff0000001000000ULL, 0x4000000000000000ULL);                   /* several ULPs above 1.0, exp=2 */
    emit(-1.0, 2.0);                                                        /* (-1)^2 = +1 (even) */
    emit(-1.0, 3.0);                                                        /* (-1)^3 = -1 (odd) */
    emit_u(0xbff0000000000001ULL, 0x4000000000000000ULL);                   /* one ULP from -1.0 (magnitude), exp=2 */

    /* --- Section 5: Integer and exact powers (12) --- */
    emit(2.0, 1.0);                                                         /* 2^1 = 2 */
    emit(2.0, 2.0);                                                         /* 2^2 = 4 */
    emit(2.0, 10.0);                                                        /* 2^10 = 1024 */
    emit(2.0, 32.0);                                                        /* 2^32 */
    emit(2.0, -1.0);                                                        /* 2^(-1) = 0.5 */
    emit(2.0, -10.0);                                                       /* 2^(-10) */
    emit(10.0, 2.0);                                                        /* 100 */
    emit(10.0, 3.0);                                                        /* 1000 */
    emit(10.0, -2.0);                                                       /* 0.01 */
    emit(3.0, 4.0);                                                         /* 81 */
    emit(4.0, 3.0);                                                         /* 64 */
    emit(5.0, 3.0);                                                         /* 125 */

    /* --- Section 6: Fractional exponents / root extraction (8) --- */
    emit(4.0, 0.5);                                                         /* sqrt(4) = 2 (exact) */
    emit(9.0, 0.5);                                                         /* sqrt(9) = 3 (exact) */
    emit(16.0, 0.25);                                                       /* 16^(1/4) = 2 (exact) */
    emit(2.0, 0.5);                                                         /* sqrt(2): irrational */
    emit(3.0, 0.5);                                                         /* sqrt(3): irrational */
    emit(0.5, 0.5);                                                         /* sqrt(0.5) = 1/sqrt(2) */
    emit(2.0, 1.0/3.0);                                                     /* 2^(1/3): cube root, inexact exponent */
    emit(8.0, 1.0/3.0);                                                     /* cbrt(8) ~ 2: inexact exponent */

    /* --- Section 7: Negative base with integer exponents (6) --- */
    emit(-2.0, 2.0);                                                        /* even: +4 */
    emit(-2.0, 3.0);                                                        /* odd: -8 */
    emit(-2.0, -1.0);                                                       /* odd negative: -0.5 */
    emit(-3.0, 2.0);                                                        /* even: +9 */
    emit(-3.0, 3.0);                                                        /* odd: -27 */
    emit(-2.0, 4.0);                                                        /* even: +16 */

    /* --- Section 8: Overflow and underflow threshold exponents (10) --- */
    emit(2.0, 1023.0);                                                      /* 2^1023: near DBL_MAX */
    emit(2.0, 1024.0);                                                      /* 2^1024: overflow -> Inf */
    emit(2.0, -1022.0);                                                     /* 2^-1022: near DBL_MIN */
    emit(2.0, -1075.0);                                                     /* 2^-1075: underflow -> 0 */
    emit(10.0, 308.0);                                                      /* 10^308: near DBL_MAX */
    emit(10.0, 309.0);                                                      /* 10^309: overflow -> Inf */
    emit(10.0, -323.0);                                                     /* 10^-323: near underflow */
    emit(10.0, -324.0);                                                     /* 10^-324: underflow -> 0 */
    emit(DBL_MAX, 2.0);                                                     /* DBL_MAX^2: overflow */
    emit(1.0e-200, 2.0);                                                    /* 1e-200^2: underflow to 0 */

    /* --- Section 9: ULP neighbors of key base/exponent boundaries (16) --- */
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);                   /* (1-ulp)^1 */
    emit_u(0x3ff0000000000000ULL, 0x3ff0000000000000ULL);                   /* 1.0^1.0 = 1 */
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);                   /* (1+ulp)^1 */
    emit_u(0x4000000000000000ULL, 0x3fefffffffffffffULL);                   /* 2.0^(1.0-ulp) */
    emit_u(0x4000000000000000ULL, 0x3ff0000000000000ULL);                   /* 2.0^1.0 = 2 */
    emit_u(0x4000000000000000ULL, 0x3ff0000000000001ULL);                   /* 2.0^(1.0+ulp) */
    emit_u(0x3fdffffffffffffeULL, 0x4000000000000000ULL);                   /* (0.5-ulp)^2 */
    emit_u(0x3fe0000000000000ULL, 0x4000000000000000ULL);                   /* 0.5^2 = 0.25 */
    emit_u(0x3fe0000000000001ULL, 0x4000000000000000ULL);                   /* (0.5+ulp)^2 */
    emit_u(0x3ff0000000000000ULL, 0x3fefffffffffffffULL);                   /* 1.0^(1-ulp) = 1 */
    emit_u(0x3ff0000000000000ULL, 0x3ff0000000000001ULL);                   /* 1.0^(1+ulp) = 1 */
    emit_u(0x4010000000000000ULL, 0x3fefffffffffffffULL);                   /* 4.0^(1-ulp): near 4 */
    emit_u(0x4010000000000000ULL, 0x3ff0000000000000ULL);                   /* 4.0^1.0 = 4 */
    emit_u(0x4010000000000000ULL, 0x3ff0000000000001ULL);                   /* 4.0^(1+ulp): near 4 */
    emit_u(0x3fe0000000000000ULL, 0x3fefffffffffffffULL);                   /* 0.5^(1-ulp) */
    emit_u(0x3fe0000000000000ULL, 0x3ff0000000000001ULL);                   /* 0.5^(1+ulp) */

    /* --- Section 10: Hard identities, negative exponent base stress, and misc (16) --- */
    emit(1.0, 0.0);                                                         /* 1^0 = 1 */
    emit(1.0, 100.0);                                                       /* 1^100 = 1 */
    emit(1.0, -100.0);                                                      /* 1^(-100) = 1 */
    emit(1.0, 1.0e15);                                                      /* 1^large = 1 */
    emit(100.0, 0.0);                                                       /* any^0 = 1 */
    emit(-5.0, 0.0);                                                        /* negative^0 = 1 */
    emit(-1.0, 1.0e15);                                                     /* (-1)^(1e15): 1e15 is odd integer -> -1 */
    emit(-1.0, 1.000000000000001e15);                                       /* (-1)^(even large int) -> +1 */
    emit(2.0, 0.5);                                                         /* pow(2, 0.5) = sqrt(2) */
    emit(1.5, 4.0);                                                         /* 1.5^4 = 5.0625 */
    emit(1.5, -4.0);                                                        /* 1.5^(-4) */
    emit(-2.0, 0.5);                                                        /* neg base, non-int exp -> NaN */
    emit(-3.0, 1.5);                                                        /* neg base, non-int exp -> NaN */
    emit(0.0, -0.0);                                                        /* 0^(-0) = 1 (special rule) */
    emit_u(0x7ff0000000000000ULL, 0xbff0000000000000ULL);                   /* +Inf^(-1) = 0 */
    emit_u(0xfff0000000000000ULL, 0xbff0000000000000ULL);                   /* -Inf^(-1) = -0 */
}

/* ------------------------------------------------------------------ */
/* Dense sweeps (accuracy path only)                                  */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep base [0.5, 10] and exponent [0, 5] */
static void test_sweep(void)
{
    int nbase = 50;
    int nexp = 50;

    for (int i = 0; i <= nbase; i++) {
        double base = 0.5 + (10.0 - 0.5) * (double)i / (double)nbase;
        for (int j = 0; j <= nexp; j++) {
            double exp = (double)j * 5.0 / (double)nexp;
            emit(base, exp);
        }
    }
}

/* 8. Sample critical range with ULP granularity */
static void test_exhaustive_small(void)
{
    /* Base in [1.0, 2.0], exponent in [0, 1] */
    uint64_t base_start = 0x3ff0000000000000ULL; /* 1.0 */
    uint64_t base_end = 0x4000000000000000ULL;   /* 2.0 */
    uint64_t exp_start = 0x0000000000000000ULL;  /* 0.0 */
    uint64_t exp_end = 0x3ff0000000000000ULL;    /* 1.0 */
    int nsteps = 16;

    for (int i = 0; i <= nsteps; i++) {
        double base = u2d(base_start) + (u2d(base_end) - u2d(base_start)) * (double)i / (double)nsteps;
        for (int j = 0; j <= nsteps; j++) {
            double exp = u2d(exp_start) + (u2d(exp_end) - u2d(exp_start)) * (double)j / (double)nsteps;
            emit(base, exp);
        }
    }
}

/* 9. Random sweep: 15x20 grid = 300 cases */
static void test_random_300(void)
{
    int nx = 15, ny = 20;
